        { name: "Unbreakable", check: "1D20 + Toughness, DC 10", damage: "Resist being knocked down", arcana: "-", weakened: "3", desc: "You steel your body and lock your stance, becoming nearly impossible to topple. On success, you cannot be knocked prone, pushed, or moved against your will for 2 rounds. You also gain +3 to resist grapple attempts. Costs 3 Weakened.", gain: 3 }
