        { name: "Shadow Cloak", check: "1D20 + Stealth, DC 10", damage: "Blend into shadows", arcana: "-", weakened: "3", desc: "You wrap the surrounding darkness around yourself like a cloak, becoming nearly invisible in dim light. On success, you gain +3 on Stealth checks and enemies must succeed on a Perception check to spot you for 2 rounds. Costs 3 Weakened.", gain: 3 },
        { name: "Disengage", check: "1D20 + Acrobatics, DC 10", damage: "Escape without provoking attack", arcana: "-", weakened: "2", desc: "You deftly slip away from your opponent, weaving out of reach before they can strike back. On success, you can move away from any number of enemies without provoking opportunity attacks this turn. Costs 2 Weakened.", gain: 0 },
        { name: "Poison Blade", check: "1D20 + Sleight of Hand, DC 10", damage: "Coat weapon with poison", arcana: "-", weakened: "3", desc: "You carefully apply a potent poison to your weapon's edge, preparing a deadly surprise for your next victim. On success, your next attack deals an additional 1D6 poison damage. The poison lasts until your next successful hit. Cannot be used during battle. Costs 3 Weakened.", gain: 0 },
        { name: "Silent Step", check: "1D20 + Stealth, DC 10", damage: "Move without making sound", arcana: "-", weakened: "2", desc: "You move with the grace of a ghost, making absolutely no sound no matter what surface you walk on. On success, your movement is completely silent, allowing you to bypass noise-based detection and sleeping guards. Cannot be used during battle. Costs 2 Weakened.", gain: 0 }
